export const supportedLocales = [
  { code: "en", label: "English" },
  { code: "zh-CN", label: "简体中文" },
  { code: "zh-TW", label: "繁體中文" },
  { code: "es", label: "Español" },
  { code: "de", label: "Deutsch" },
  { code: "fr", label: "Français" },
  { code: "ja", label: "日本語" },
  { code: "pt", label: "Português" },
  { code: "ko", label: "한국어" },
] as const;

export type UiLocale = (typeof supportedLocales)[number]["code"];
export type TranslationVars = Record<string, string | number>;
export const defaultLocale: UiLocale = "en";

export function resolveLocale(value?: string | null): UiLocale {
  return supportedLocales.some((item) => item.code === value) ? value as UiLocale : defaultLocale;
}

